import React from 'react';
import { Link } from 'react-router-dom';
import { ArrowRight } from 'lucide-react';
import { motion } from 'framer-motion';

const skills = [
    { category: 'Frontend', items: [{ name: 'React', level: 90 }, { name: 'Tailwind CSS', level: 85 }, { name: 'JavaScript / TS', level: 80 }] },
    { category: 'Backend', items: [{ name: 'Node.js', level: 75 }, { name: 'Express', level: 70 }, { name: 'MongoDB', level: 65 }] },
    { category: 'Tools', items: [{ name: 'Git & GitHub', level: 85 }, { name: 'Docker', level: 60 }, { name: 'Figma', level: 70 }] },
];

const About = () => {
    return (
        <section id="about" className="py-32 border-t border-white/5 relative bg-grid">
            <motion.div
                initial={{ opacity: 0, y: 30 }}
                whileInView={{ opacity: 1, y: 0 }}
                viewport={{ once: true, margin: "-100px" }}
                transition={{ duration: 1 }}
            >
                <div className="grid lg:grid-cols-2 gap-24 items-start">
                    {/* Bio Column */}
                    <div className="space-y-12">
                        <div className="space-y-4">
                            <h2 className="text-4xl md:text-5xl font-black text-accent2 tracking-tighter font-heading italic">
                                About <span className="text-gradient">Me</span>
                            </h2>
                            <div className="w-16 h-1.5 bg-accent1 rounded-full" />
                        </div>

                        <div className="space-y-8 text-primary leading-relaxed text-lg md:text-xl font-light">
                            <p>
                                I am a results-driven <span className="text-accent2 font-bold italic">Software Engineer</span> with a passion for designing and building highly scalable, resilient web architectures.
                            </p>
                            <p>
                                My methodology prioritizes <span className="text-accent2 font-bold italic">engineering excellence</span>, focusing on well-tested, maintainable codebases over quick patches. Whether crafting pixel-perfect UIs or optimizing server-side orchestration, my goal is to deliver premium digital experiences.
                            </p>
                            <p>
                                With a strong foundation in <span className="text-accent1 font-bold italic">Full-Stack Development</span>, I bridge the gap between complex logic and intuitive user experiences.
                            </p>
                        </div>

                        <Link to="/about" className="inline-flex items-center gap-6 px-10 py-5 glass-card text-accent2 font-black rounded-[2rem] hover:bg-white/5 hover:-translate-y-1 transition-all duration-500 group uppercase tracking-widest text-xs border border-white/5">
                            The Full Narrative
                            <ArrowRight size={18} className="group-hover:translate-x-1 transition-transform text-accent1" />
                        </Link>
                    </div>

                    {/* Skills Column */}
                    <div className="glass-card p-12 space-y-12 border border-white/5 hover:border-accent1/20 transition-all duration-700 shadow-[0_64px_128px_-16px_rgba(0,0,0,0.6)] bg-surface/10">
                        <h3 className="text-2xl font-black text-accent2 font-heading uppercase tracking-widest italic">Technical Arsenal</h3>
                        <div className="space-y-10">
                            {skills.map((skillGroup, idx) => (
                                <div key={idx} className="space-y-8">
                                    <h4 className="text-[10px] font-black text-secondary uppercase tracking-[0.4em]">{skillGroup.category}</h4>
                                    <div className="space-y-7">
                                        {skillGroup.items.map((skill, i) => (
                                            <div key={i} className="group">
                                                <div className="flex justify-between text-sm mb-3">
                                                    <span className="text-primary font-bold group-hover:text-accent1 transition-colors uppercase tracking-widest text-[11px]">{skill.name}</span>
                                                    <span className="text-secondary font-mono text-xs">{skill.level}%</span>
                                                </div>
                                                <div className="w-full h-1 bg-white/5 rounded-full overflow-hidden">
                                                    <motion.div
                                                        className="h-full bg-gradient-to-r from-accent1 to-gold-light"
                                                        initial={{ width: 0 }}
                                                        whileInView={{ width: `${skill.level}%` }}
                                                        viewport={{ once: true }}
                                                        transition={{ duration: 1.8, delay: 0.2, ease: "circOut" }}
                                                    />
                                                </div>
                                            </div>
                                        ))}
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>
                </div>
            </motion.div>
        </section>
    );
};

export default About;

import React from 'react';
import { Award, Medal, Trophy, Star } from 'lucide-react';
import { motion } from 'framer-motion';

const achievements = [
    {
        title: "Google Cloud Certified - Associate Cloud Engineer",
        organization: "Google",
        date: "2024",
        description: "Demonstrated ability to deploy applications, monitor operations, and manage enterprise solutions on Google Cloud.",
        icon: Award,
    },
    {
        title: "AWS Certified Solutions Architect",
        organization: "Amazon Web Services",
        date: "2023",
        description: "Validated expertise in designing distributed systems and deploying applications on the AWS platform.",
        icon: Trophy,
    },
    {
        title: "1st Place - National Hackathon",
        organization: "Tech Innovators",
        date: "2023",
        description: "Led a team of 4 to build an AI-powered healthcare application within 48 hours, winning the grand prize among 500+ teams.",
        icon: Medal,
    },
    {
        title: "Outstanding Performance Award",
        organization: "Previous Company Inc.",
        date: "2022",
        description: "Recognized for delivering a critical microservices migration project 2 months ahead of schedule.",
        icon: Star,
    }
];

const Achievements = () => {
    return (
        <section id="achievements" className="py-32 border-t border-white/5 relative bg-grid">
            <div className="mb-20 text-center space-y-4">
                <h2 className="text-4xl md:text-5xl font-black text-accent2 tracking-tighter font-heading italic">
                    Milestones & <span className="text-gradient">Accolades</span>
                </h2>
                <p className="text-primary max-w-2xl mx-auto text-lg md:text-xl font-light">
                    A curated archive of professional certifications, high-impact awards, and technical milestones.
                </p>
            </div>

            <div className="grid md:grid-cols-2 gap-10 relative z-10">
                {achievements.map((item, i) => {
                    const Icon = item.icon;
                    return (
                        <motion.div
                            key={i}
                            className="glass-card p-10 group hover:-translate-y-4 transition-all duration-700 ease-out hover:shadow-[0_48px_96px_-16px_rgba(0,0,0,0.6)] hover:border-accent1/30 flex flex-col sm:flex-row gap-8 items-start relative overflow-hidden bg-surface/5 border border-white/5"
                            initial={{ opacity: 0, y: 50 }}
                            whileInView={{ opacity: 1, y: 0 }}
                            viewport={{ once: true, margin: "-50px" }}
                            transition={{ duration: 1, delay: i * 0.1 }}
                        >
                            <div className="absolute inset-0 bg-gradient-to-br from-accent1/5 to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-700 pointer-events-none" />
                            <div className="p-6 bg-background/50 backdrop-blur-xl border border-white/5 rounded-[2rem] text-accent1 group-hover:scale-110 group-hover:bg-accent1 group-hover:text-background transition-all duration-700 relative z-10 shadow-2xl group-hover:shadow-[0_0_30px_rgba(194,160,122,0.4)]">
                                <Icon size={36} />
                            </div>
                            <div className="space-y-4">
                                <div className="space-y-1">
                                    <h3 className="text-2xl font-black text-accent2 group-hover:text-accent1 transition-all duration-500 font-heading tracking-tight italic">{item.title}</h3>
                                    <div className="flex items-center gap-3">
                                        <span className="text-[10px] font-black text-secondary uppercase tracking-[0.3em]">{item.organization}</span>
                                        <span className="w-1.5 h-1.5 rounded-full bg-accent1/40" />
                                        <span className="text-xs font-mono text-secondary opacity-60">{item.date}</span>
                                    </div>
                                </div>
                                <p className="text-primary text-base leading-relaxed font-light line-clamp-3">
                                    {item.description}
                                </p>
                            </div>
                        </motion.div>
                    );
                })}
            </div>
        </section>
    );
};

export default Achievements;

import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { MapPin, Github, Linkedin, Twitter, Copy, ArrowUpRight, Sparkles } from 'lucide-react';

const BentoGrid = () => {
    const [currentTime, setCurrentTime] = useState('');
    const [copied, setCopied] = useState(false);

    useEffect(() => {
        const updateTime = () => {
            const now = new Date();
            setCurrentTime(now.toLocaleTimeString('en-US', {
                hour: '2-digit',
                minute: '2-digit',
                hour12: true,
                timeZone: 'Asia/Kolkata'
            }));
        };
        updateTime();
        const interval = setInterval(updateTime, 1000);
        return () => clearInterval(interval);
    }, []);

    const handleCopyEmail = () => {
        navigator.clipboard.writeText('ahalyajena28@gmail.com');
        setCopied(true);
        setTimeout(() => setCopied(false), 2000);
    };

    const cardVariants = {
        hidden: { opacity: 0, y: 40, scale: 0.95 },
        visible: (i) => ({
            opacity: 1, y: 0, scale: 1,
            transition: { delay: i * 0.1, duration: 0.7, ease: [0.25, 0.46, 0.45, 0.94] }
        })
    };

    const philosophyTags = ['Motion', 'Type', 'Feedback', 'Craft'];
    const [activeTag, setActiveTag] = useState(0);

    useEffect(() => {
        const interval = setInterval(() => {
            setActiveTag(prev => (prev + 1) % philosophyTags.length);
        }, 2000);
        return () => clearInterval(interval);
    }, []);

    return (
        <section className="relative py-6 px-4 sm:px-6 lg:px-8 max-w-7xl mx-auto">
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4 auto-rows-auto">

                {/* Card 1: Profile Card */}
                <motion.div
                    className="bento-card p-6 md:p-8 flex flex-col justify-between row-span-2 min-h-[380px]"
                    custom={0}
                    variants={cardVariants}
                    initial="hidden"
                    whileInView="visible"
                    viewport={{ once: true, margin: "-50px" }}
                >
                    <div>
                        <h3 className="text-2xl font-heading text-white">
                            Ayush <span className="font-serif italic text-accent2">Kumar Jena</span>
                        </h3>
                        <div className="flex items-center gap-2 mt-3 text-secondary text-xs">
                            <MapPin size={12} />
                            <span>Sambalpur, IN</span>
                            <span className="text-white/20 mx-1">•</span>
                            <span>{currentTime}</span>
                        </div>
                    </div>

                    {/* Photo Gallery */}
                    <div className="mt-6 flex gap-3 overflow-hidden">
                        <div className="w-1/3 aspect-[3/4] rounded-2xl bg-gradient-to-br from-blue-900/60 to-purple-900/60 overflow-hidden">
                            <img src="/profile.jpg" alt="Ayush" className="w-full h-full object-cover opacity-80 hover:opacity-100 transition-opacity duration-500 hover:scale-105" />
                        </div>
                        <div className="w-1/3 aspect-[3/4] rounded-2xl bg-gradient-to-br from-orange-900/40 to-amber-900/40 overflow-hidden flex items-center justify-center">
                            <div className="text-4xl">🚀</div>
                        </div>
                        <div className="w-1/3 aspect-[3/4] rounded-2xl bg-gradient-to-br from-emerald-900/40 to-teal-900/40 overflow-hidden flex items-center justify-center">
                            <div className="text-4xl">💡</div>
                        </div>
                    </div>

                    {/* Social Icons */}
                    <div className="flex items-center gap-4 mt-6">
                        <a href="https://www.linkedin.com/in/ayush-kumar-jena-5a0b24212/" target="_blank" rel="noopener noreferrer" className="text-secondary hover:text-white transition-colors">
                            <Linkedin size={18} />
                        </a>
                        <a href="https://github.com/ayushkumarjena15" target="_blank" rel="noopener noreferrer" className="text-secondary hover:text-white transition-colors">
                            <Github size={18} />
                        </a>
                        <a href="#" className="text-secondary hover:text-white transition-colors">
                            <Twitter size={18} />
                        </a>
                    </div>
                </motion.div>

                {/* Card 2: Philosophy/Interfaces */}
                <motion.div
                    className="bento-card p-6 md:p-8 flex flex-col justify-between min-h-[180px]"
                    custom={1}
                    variants={cardVariants}
                    initial="hidden"
                    whileInView="visible"
                    viewport={{ once: true, margin: "-50px" }}
                >
                    <div>
                        <div className="flex items-center gap-2 text-secondary text-[10px] uppercase tracking-[0.3em] font-bold mb-3">
                            <Sparkles size={12} className="text-accent1" />
                            <span>Detail-Driven UI</span>
                        </div>
                        <h3 className="text-2xl md:text-3xl font-heading font-bold text-white leading-tight">
                            Interfaces
                        </h3>
                        <p className="text-xl md:text-2xl font-serif italic text-accent1 mt-1">
                            you can feel.
                        </p>
                    </div>

                    <div className="flex flex-wrap gap-2 mt-4">
                        {philosophyTags.map((tag, i) => (
                            <span
                                key={tag}
                                className={`px-3 py-1.5 text-[10px] font-bold uppercase tracking-wider rounded-full border transition-all duration-500 ${activeTag === i
                                        ? 'bg-accent1 border-accent1 text-background'
                                        : 'border-white/10 text-secondary'
                                    }`}
                            >
                                {tag}
                            </span>
                        ))}
                    </div>

                    <div className="mt-4">
                        <p className="text-[10px] uppercase tracking-[0.2em] text-secondary font-bold">Philosophy ✦</p>
                        <p className="text-sm font-bold text-white mt-1">Micro-interactions</p>
                        <p className="text-xs text-secondary mt-1 leading-relaxed">
                            Subtle movement that confirms intent — never distracting.
                        </p>
                    </div>
                </motion.div>

                {/* Card 3: Connect / Available for Work */}
                <motion.div
                    className="bento-card p-6 md:p-8 flex flex-col justify-between row-span-2 min-h-[380px]"
                    custom={2}
                    variants={cardVariants}
                    initial="hidden"
                    whileInView="visible"
                    viewport={{ once: true, margin: "-50px" }}
                >
                    {/* Available badge */}
                    <div className="flex items-center justify-between">
                        <div className="w-8 h-8 rounded-full bg-white/10 flex items-center justify-center">
                            <div className="w-2 h-2 rounded-full bg-white" />
                        </div>
                        <div className="flex items-center gap-2 px-3 py-1.5 rounded-full bg-green-500/10 border border-green-500/20">
                            <div className="w-2 h-2 rounded-full bg-green-500 animate-pulse" />
                            <span className="text-[10px] font-bold text-green-400 uppercase tracking-wider">Available for work</span>
                        </div>
                    </div>

                    <div className="mt-6">
                        <h3 className="text-2xl md:text-3xl font-heading font-black text-white leading-tight uppercase">
                            Let's Build<br />Something
                        </h3>
                        <p className="text-xl font-serif italic text-secondary mt-1">
                            that actually works.
                        </p>
                    </div>

                    {/* Email */}
                    <div className="mt-6 space-y-3">
                        <div
                            onClick={handleCopyEmail}
                            className="flex items-center gap-3 cursor-pointer group"
                        >
                            <div className="w-8 h-8 rounded-full bg-white/5 flex items-center justify-center border border-white/10 group-hover:border-accent1/30 transition-colors">
                                <Copy size={12} className="text-secondary group-hover:text-accent1 transition-colors" />
                            </div>
                            <div>
                                <p className="text-sm font-bold text-white font-serif italic">ahalyajena28@gmail.com</p>
                                <p className="text-[10px] text-secondary uppercase tracking-widest mt-0.5">
                                    {copied ? '✓ COPIED!' : 'TAP TO COPY EMAIL'}
                                </p>
                            </div>
                        </div>
                    </div>

                    {/* Connect Button */}
                    <a
                        href="mailto:ahalyajena28@gmail.com"
                        className="mt-6 w-full py-4 border border-white/20 rounded-xl text-center text-xs font-bold uppercase tracking-[0.2em] text-white hover:bg-white hover:text-background transition-all duration-500 flex items-center justify-center gap-2"
                    >
                        Connect Now
                        <ArrowUpRight size={14} />
                    </a>
                </motion.div>

                {/* Card 4: Clock Widget */}
                <motion.div
                    className="bento-card p-0 overflow-hidden flex items-center justify-center min-h-[200px] relative"
                    custom={3}
                    variants={cardVariants}
                    initial="hidden"
                    whileInView="visible"
                    viewport={{ once: true, margin: "-50px" }}
                >
                    <AnalogClock />
                </motion.div>

                {/* Card 5: Founder Card */}
                <motion.div
                    className="bento-card md:col-span-2 p-6 md:p-8 flex flex-col md:flex-row gap-8 items-start min-h-[180px]"
                    custom={4}
                    variants={cardVariants}
                    initial="hidden"
                    whileInView="visible"
                    viewport={{ once: true, margin: "-50px" }}
                >
                    {/* Globe Section */}
                    <div className="flex-1 space-y-4">
                        <p className="text-[10px] text-green-400 uppercase tracking-[0.3em] font-bold">Available Globally</p>
                        <h3 className="text-xl font-heading font-bold text-white">
                            Adaptable across<br />time zones
                        </h3>
                        <div className="mt-4 flex flex-wrap gap-2">
                            {['🇬🇧 UK', '🇮🇳 India', '🇺🇸 USA'].map((zone, i) => (
                                <span
                                    key={zone}
                                    className={`px-4 py-2 rounded-full text-xs font-bold border transition-all ${i === 1
                                            ? 'bg-accent1/20 border-accent1/40 text-accent1'
                                            : 'border-white/10 text-secondary'
                                        }`}
                                >
                                    {zone}
                                </span>
                            ))}
                        </div>
                    </div>

                    {/* Founder Info */}
                    <div className="flex-1 text-right space-y-3">
                        <h3 className="text-2xl md:text-3xl font-heading font-black text-white">
                            Creator of <span className="text-red-500 font-serif italic">SkillTwin</span>
                        </h3>
                        <p className="text-secondary text-sm italic flex items-center justify-end gap-2">
                            &lt; Crafting Digital Experiences /&gt;
                            <ArrowUpRight size={14} className="text-accent1" />
                        </p>
                    </div>
                </motion.div>

                {/* Card 6: Detail Card with I sweat spacing */}
                <motion.div
                    className="bento-card p-6 md:p-8 min-h-[120px] flex flex-col justify-center"
                    custom={5}
                    variants={cardVariants}
                    initial="hidden"
                    whileInView="visible"
                    viewport={{ once: true, margin: "-50px" }}
                >
                    <p className="text-sm text-secondary leading-relaxed">
                        I sweat spacing, timing, and feedback —<br />
                        <span className="text-primary font-medium">the tiny stuff.</span>
                    </p>
                </motion.div>

            </div>
        </section>
    );
};

// Analog Clock Component
const AnalogClock = () => {
    const [time, setTime] = useState(new Date());

    useEffect(() => {
        const interval = setInterval(() => setTime(new Date()), 1000);
        return () => clearInterval(interval);
    }, []);

    // IST offset
    const utc = time.getTime() + (time.getTimezoneOffset() * 60000);
    const ist = new Date(utc + (5.5 * 3600000));

    const seconds = ist.getSeconds();
    const minutes = ist.getMinutes();
    const hours = ist.getHours() % 12;

    const secondDeg = seconds * 6;
    const minuteDeg = minutes * 6 + seconds * 0.1;
    const hourDeg = hours * 30 + minutes * 0.5;

    return (
        <div className="relative w-full h-full flex items-center justify-center bg-gradient-to-b from-[#111] to-[#0a0a0a] min-h-[200px]">
            <div className="relative w-40 h-40 md:w-48 md:h-48">
                {/* Watch face */}
                <div className="absolute inset-0 rounded-full border-2 border-white/10 bg-[#0a0a0a]">
                    {/* Hour markers */}
                    {[...Array(12)].map((_, i) => (
                        <div
                            key={i}
                            className="absolute w-full h-full"
                            style={{ transform: `rotate(${i * 30}deg)` }}
                        >
                            <div className={`absolute top-2 left-1/2 -translate-x-1/2 ${i % 3 === 0 ? 'w-0.5 h-3 bg-white/80' : 'w-px h-2 bg-white/30'}`} />
                        </div>
                    ))}

                    {/* Hour numbers */}
                    {[12, 3, 6, 9].map((num) => {
                        const angle = (num * 30 - 90) * (Math.PI / 180);
                        const radius = 32;
                        const x = 50 + radius * Math.cos(angle);
                        const y = 50 + radius * Math.sin(angle);
                        return (
                            <span
                                key={num}
                                className="absolute text-[10px] font-bold text-white/60"
                                style={{
                                    left: `${x}%`,
                                    top: `${y}%`,
                                    transform: 'translate(-50%, -50%)',
                                }}
                            >
                                {num}
                            </span>
                        );
                    })}

                    {/* Hour hand */}
                    <div
                        className="absolute bottom-1/2 left-1/2 w-[3px] h-[28%] bg-white rounded-full origin-bottom -translate-x-1/2 transition-transform"
                        style={{ transform: `translateX(-50%) rotate(${hourDeg}deg)` }}
                    />
                    {/* Minute hand */}
                    <div
                        className="absolute bottom-1/2 left-1/2 w-[2px] h-[36%] bg-white/80 rounded-full origin-bottom -translate-x-1/2 transition-transform"
                        style={{ transform: `translateX(-50%) rotate(${minuteDeg}deg)` }}
                    />
                    {/* Second hand */}
                    <div
                        className="absolute bottom-1/2 left-1/2 w-px h-[40%] bg-accent1 rounded-full origin-bottom -translate-x-1/2"
                        style={{ transform: `translateX(-50%) rotate(${secondDeg}deg)` }}
                    />
                    {/* Center dot */}
                    <div className="absolute top-1/2 left-1/2 w-2 h-2 bg-accent1 rounded-full -translate-x-1/2 -translate-y-1/2 z-10" />
                </div>
            </div>
        </div>
    );
};

export default BentoGrid;

import React, { useEffect, useRef } from 'react';
import { motion } from 'framer-motion';

const CTASection = () => {
    const canvasRef = useRef(null);

    useEffect(() => {
        const canvas = canvasRef.current;
        if (!canvas) return;
        const ctx = canvas.getContext('2d');
        let animationId;
        let hue = 0;

        const resize = () => {
            canvas.width = 200;
            canvas.height = 200;
        };
        resize();

        const draw = () => {
            ctx.clearRect(0, 0, 200, 200);
            const cx = 100;
            const cy = 100;
            const r = 70;

            // Glowing ring
            for (let i = 0; i < 360; i += 2) {
                const angle = (i * Math.PI) / 180;
                const x = cx + r * Math.cos(angle);
                const y = cy + r * Math.sin(angle);

                const colorHue = (hue + i) % 360;
                ctx.beginPath();
                ctx.arc(x, y, 3, 0, Math.PI * 2);
                ctx.fillStyle = `hsla(${colorHue}, 70%, 60%, 0.6)`;
                ctx.fill();
            }

            // Inner glow
            const gradient = ctx.createRadialGradient(cx, cy, 0, cx, cy, r);
            gradient.addColorStop(0, `hsla(${hue}, 60%, 50%, 0.05)`);
            gradient.addColorStop(1, 'transparent');
            ctx.fillStyle = gradient;
            ctx.fillRect(0, 0, 200, 200);

            hue = (hue + 0.5) % 360;
            animationId = requestAnimationFrame(draw);
        };

        draw();
        return () => cancelAnimationFrame(animationId);
    }, []);

    return (
        <section className="py-32 px-4 sm:px-6 lg:px-8 max-w-7xl mx-auto relative">
            <div className="flex flex-col lg:flex-row items-center justify-between gap-16">
                {/* Text */}
                <motion.div
                    className="flex-1"
                    initial={{ opacity: 0, x: -40 }}
                    whileInView={{ opacity: 1, x: 0 }}
                    viewport={{ once: true }}
                    transition={{ duration: 0.8 }}
                >
                    <h2 className="text-5xl md:text-7xl font-heading font-black text-white leading-tight flex items-start gap-4">
                        <span className="text-3xl mt-2">👋</span>
                        <span>
                            Let's create<br />
                            <span className="text-secondary font-light">something real.</span>
                        </span>
                    </h2>
                </motion.div>

                {/* Animated Ring */}
                <motion.div
