                                        </span>
                                    ))}
                                </div>
                            </div>

                            {/* Right - Mockup */}
                            <div className={`rounded-3xl bg-gradient-to-br ${venture.color} p-6 md:p-8 overflow-hidden relative group cursor-pointer`}>
                                <div className="relative z-10">
