                                        >
                                            <defs>
                                                <path
                                                    id={`circlePath-${idx}`}
                                                    d="M100,100 m-70,0 a70,70 0 1,1 140,0 a70,70 0 1,1 -140,0"
                                                />
                                            </defs>
                                            <text fill="white" fontSize="14" fontWeight="700" letterSpacing="6" textTransform="uppercase">
